mapper.select:
        SELECT NVL(MAX(file_version), 0)
		FROM attach_file
		WHERE project_id = #{projectId}
  			AND connect_address = #{connectAddress}
  			AND original_name = #{originalName}

  SELECT NVL(MAX(file_version), 0) + 1
  FROM attach_file
  WHERE project_id = #{projectId}
			AND connect_address = #{connectAddress}
			AND original_name = #{originalName}

select file_id, project_id, version_id, file_code, original_name, stored_name, file_path, file_size, upload_user_id, upload_date, file_version, file_use_yn from attach_file where connect_address = #{connectAddress}
AND document_version_id = #{documentVersionId}
ORDER BY upload_date DESC
